PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?player ?playerLabel
WHERE {
  ?season1 wdt:P31 wd:Q165257;
             wdt:P12475 ?player;
             wdt:P585 ?time1.
  ?season2 wdt:P31 wd:Q165257;
             wdt:P12475 ?player;
             wdt:P585 ?time2.
  ?season3 wdt:P31 wd:Q165257;
             wdt:P12475 ?player;
             wdt:P585 ?time3.
  BIND(YEAR(?time1) AS ?year1)
  BIND(YEAR(?time2) AS ?year2)
  BIND(YEAR(?time3) AS ?year3)
  FILTER(?year2 = ?year1 + 1)
  FILTER(?year3 = ?year2 + 1)
  OPTIONAL { ?player rdfs:label ?playerLabel. FILTER(LANG(?playerLabel) = "en") }
}
LIMIT 100

