PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?player ?playerLabel ?minYear ?maxYear ?count
WHERE {
  {
    SELECT ?player (MIN(?year) AS ?minYear) (MAX(?year) AS ?maxYear) (COUNT(?season) AS ?count)
    WHERE {
      ?season wdt:P31 wd:Q165257;  # NBA season
              wdt:P1662 ?player;      # NBA scoring leader
              wdt:P582 ?end.
      BIND(YEAR(?end) AS ?year)
    }
    GROUP BY ?player
    HAVING (COUNT(?season) >= 3)
  }
  FILTER (?maxYear - ?minYear + 1 = ?count)
  OPTIONAL { ?player rdfs:label ?playerLabel FILTER(LANG(?playerLabel) = "en") }
}
ORDER BY DESC(?count)

